solution_code:
#include <iostream>
#include <stdexcept>

void dispatch(int code) {
    if (code == 1) throw std::runtime_error("runtime");
    if (code == 2) throw std::invalid_argument("invalid");
    if (code == 3) throw 42;
}

int main() {
    int code;
    std::cin >> code;

    try {
        dispatch(code);
        std::cout << "no exception\n";
    } catch (const std::runtime_error& e) {
        std::cout << "runtime_error: " << e.what() << "\n";
    } catch (const std::invalid_argument& e) {
        std::cout << "invalid_argument: " << e.what() << "\n";
    } catch (int val) {
        std::cout << "int exception: " << val << "\n";
    }

    return 0;
}

