solution_code:
#include <iostream>
#include <stdexcept>
#include <string>

std::string grade_letter(int score) {
    if (score < 0 || score > 100)
        throw std::out_of_range("score out of range");
    if (score >= 90) return "A";
    if (score >= 80) return "B";
    if (score >= 70) return "C";
    if (score >= 60) return "D";
    return "F";
}

int main() {
    int score;
    std::cin >> score;

    try {
        std::string g = grade_letter(score);
        std::cout << "Grade: " << g << "\n";
    } catch (const std::out_of_range& e) {
        std::cout << "Error: score out of range\n";
    }

    return 0;
}
